const url = $input.item.json.url || '';
const urlLower = url.toLowerCase();

// List of domains to skip
const skipDomains = [
  'youtube.com',
  'youtu.be',
  'vimeo.com',
  'twitch.tv',
  'facebook.com',
  'twitter.com',
  'instagram.com'
];

// Check if URL contains any skip domain
const shouldSkip = skipDomains.some(domain => urlLower.includes(domain));

return {
  json: {
    id: $input.item.json.id,
    url: url,
    country: $input.item.json.country,
    domain: $input.item.json.domain,
    domain_for_searching: $input.item.json.domain_for_searching,
    shouldSkip: shouldSkip,
    skipReason: shouldSkip ? 'Video/social media platform' : null
  }
};

// n8n Function node to classify if a website is an affiliate site
// Get data directly from the HTTP Request node output

const inputUrl = $input.first().json.url || '';
const html = $input.first().json.rendered_html_tags || '';

const text = html ? html.toLowerCase() : '';

// Debug output if something is wrong
if (!html || html.length < 100) {
  return {
    json: {
      url: inputUrl,
      classification: 'ERROR',
      error: 'No HTML content received or content too short',
      debug: {
        htmlLength: html ? html.length : 0,
        sampleData: html ? html.substring(0, 200) : 'No HTML'
      }
    }
  };
}

// Helper function to count occurrences
function countOccurrences(str, patterns) {
  let count = 0;
  patterns.forEach(pattern => {
    const regex = new RegExp(pattern, 'gi');
    const matches = str.match(regex);
    if (matches) count += matches.length;
  });
  return count;
}

// Helper function to get domain
function getDomain(urlString) {
  try {
    if (!urlString.startsWith('http')) {
      return null;
    }
    const urlObj = new URL(urlString);
    return urlObj.hostname;
  } catch (e) {
    return null;
  }
}

// IMPROVED: Helper function to count casino outbound links (including redirects/tracking links)
function countCasinoOutboundLinks(html, currentUrl) {
  let currentDomain;
  try {
    currentDomain = new URL(currentUrl).hostname;
  } catch (e) {
    currentDomain = '';
  }

  const hrefPattern = /href=["']([^"']+)["']/gi;
  const matches = html.matchAll(hrefPattern);

  const externalCasinoDomains = new Set();
  const casinoTrackingLinks = new Set();
  const casinoKeywords = ['casino', 'bet', 'gaming', 'slots', 'poker', 'blackjack', 'spin'];

  for (const match of matches) {
    let link = match[1];

    // Skip anchors, javascript, mailto, tel
    if (link.startsWith('#') || link.startsWith('javascript:') || 
        link.startsWith('mailto:') || link.startsWith('tel:')) {
      continue;
    }

    // Normalize link for checking
    const linkLower = link.toLowerCase();

    // Check for tracking/redirect links (common in affiliate sites)
    // Patterns: /track/, /click/, /go/, /visit/, /out/, /redirect/, /creat/, /aff/, /ref/, /link/
    // Also check for query parameters like ?ref=, ?aff=, ?campaign=
    const isTrackingLink = link.match(/\/(track|click|go|visit|out|redirect|creat|aff|ref|link|offer|bonus|promo)\//i) ||
                          link.match(/[?&](ref|aff|affiliate|campaign|source|tracking|click)=/i);

    if (isTrackingLink) {
      casinoTrackingLinks.add(link);
      continue;
    }

    // Check for direct external casino links
    if (link.startsWith('http')) {
      const linkDomain = getDomain(link);
      if (linkDomain && linkDomain !== currentDomain) {
        if (casinoKeywords.some(kw => linkDomain.includes(kw) || linkLower.includes(kw))) {
          externalCasinoDomains.add(linkDomain);
        }
      }
    }
  }

  // Return the larger count (either direct links or tracking links)
  return Math.max(externalCasinoDomains.size, casinoTrackingLinks.size);
}

// Initialize scores and indicators
let affiliateScore = 0;
let casinoScore = 0;
const indicators = [];

// Count external casino links first (critical for classification)
const externalCasinoCount = countCasinoOutboundLinks(html, inputUrl);

// === PRIMARY DECISION FACTOR: External Casino Links ===

if (externalCasinoCount >= 5) {
  affiliateScore += 15;
  indicators.push(`✓✓ Multiple outbound casino links (${externalCasinoCount}) - STRONG AFFILIATE SIGNAL`);
} else if (externalCasinoCount >= 3) {
  affiliateScore += 10;
  indicators.push(`✓ Several outbound casino links (${externalCasinoCount})`);
} else if (externalCasinoCount >= 1) {
  affiliateScore += 3;
  indicators.push(`○ Some outbound casino links (${externalCasinoCount})`);
}

// === AFFILIATE INDICATORS ===

// 1. Check for affiliate disclosure
const affiliateDisclosures = [
  'we may earn', 'earn commission', 'affiliate commission', 
  'compensated for referring', 'advertising disclosure', 'affiliate disclaimer'
];
const affiliateDisclosureFound = affiliateDisclosures.some(phrase => text.includes(phrase));
if (affiliateDisclosureFound) {
  affiliateScore += 8;
  indicators.push('✓✓ Affiliate disclosure found');
}

// 2. Check for comparison/review language
const reviewKeywords = [
  'best online casino', 'top casino', 'casino review', 'compare casino',
  'casino ranking', 'casino comparison', 'casino list', 
  'recommended casino', 'top 10', 'top 25', 'top 20'
];
const reviewCount = countOccurrences(text, reviewKeywords);
if (reviewCount >= 5) {
  affiliateScore += 7;
  indicators.push(`✓✓ Heavy review/comparison language (${reviewCount})`);
} else if (reviewCount >= 2) {
  affiliateScore += 4;
  indicators.push(`✓ Review/comparison language (${reviewCount})`);
}

// 3. Multiple CTAs to OTHER casinos
const ctaPatterns = ['visit casino', 'visit site', 'go to casino', 'claim at', 'play at', 'get bonus', 'claim bonus'];
const ctaCount = countOccurrences(text, ctaPatterns);
if (ctaCount >= 10) {
  affiliateScore += 6;
  indicators.push(`✓ Many external CTAs (${ctaCount})`);
} else if (ctaCount >= 5) {
  affiliateScore += 3;
  indicators.push(`○ Several CTAs (${ctaCount})`);
}

// 4. Bonus comparison content
const bonusComparisonKeywords = ['welcome bonus', 'bonus offer', 'free spins', 'match bonus', 'deposit bonus'];
const bonusCompCount = countOccurrences(text, bonusComparisonKeywords);
if (bonusCompCount >= 10) {
  affiliateScore += 5;
  indicators.push(`✓ Heavy bonus comparison content (${bonusCompCount})`);
} else if (bonusCompCount >= 5) {
  affiliateScore += 2;
  indicators.push(`○ Bonus content (${bonusCompCount})`);
}

// 5. Pros/cons structure (common in affiliate reviews)
const hasProsConsStructure = (text.includes('pros:') || text.includes('pros') || text.includes('advantages:')) && 
                              (text.includes('cons:') || text.includes('cons') || text.includes('disadvantages:'));
if (hasProsConsStructure) {
  affiliateScore += 5;
  indicators.push('✓ Pros/cons review structure');
}

// 6. Rating system
const hasRatings = /\d+(\.\d+)?\s*(\/|out of)\s*\d+|★{2,}|⭐{2,}|rating/i.test(html);
if (hasRatings) {
  affiliateScore += 3;
  indicators.push('✓ Rating system detected');
}

// 7. Comparison table
const hasTable = /<table/i.test(html);
if (hasTable && (text.includes('casino') || text.includes('bonus'))) {
  affiliateScore += 4;
  indicators.push('✓ Comparison table structure');
}

// 8. "Play Now" buttons with rel="nofollow" or "noopener"
const hasNoFollowPlayButtons = /rel=["'][^"']*nofollow[^"']*["']/i.test(html) || 
                                 /rel=["'][^"']*noopener[^"']*["']/i.test(html);
if (hasNoFollowPlayButtons) {
  affiliateScore += 5;
  indicators.push('✓ Affiliate-style link markers detected');
}

// === CASINO INDICATORS ===

// 1. Login/Registration forms - ONLY if no outbound casino links
const hasLoginKeywords = text.includes('log in') || text.includes('sign in') || text.includes('login');
const hasRegisterKeywords = text.includes('register') || text.includes('sign up') || text.includes('join now');
const hasPasswordField = html.includes('type="password"') || html.includes("type='password'");

if ((hasLoginKeywords || hasRegisterKeywords) && hasPasswordField && externalCasinoCount === 0) {
  casinoScore += 12;
  indicators.push('✓✓ Login/registration system (CASINO)');
}

// 2. Deposit/withdrawal - reduce weight if high affiliate score
const depositWithdrawKeywords = ['deposit now', 'make a deposit', 'withdraw funds', 'cashier', 'my wallet'];
const depositCount = countOccurrences(text, depositWithdrawKeywords);

// If affiliate score is already high, don't give much weight to deposit mentions
if (depositCount >= 5 && externalCasinoCount === 0 && affiliateScore < 15) {
  casinoScore += 10;
  indicators.push(`✓✓ Deposit/withdrawal system (${depositCount}) (CASINO)`);
} else if (depositCount >= 3 && externalCasinoCount === 0 && affiliateScore < 20) {
  casinoScore += 5;
  indicators.push(`○ Payment mentions (${depositCount})`);
}

// 3. Account/Balance
const accountKeywords = ['my account', 'account balance', 'my balance', 'player account', 'account settings'];
const accountCount = countOccurrences(text, accountKeywords);
if (accountCount >= 3 && externalCasinoCount === 0) {
  casinoScore += 8;
  indicators.push(`✓ Player account system (${accountCount}) (CASINO)`);
}

// 4. Responsible gambling tools
const responsibleGamblingKeywords = ['responsible gambling', 'self-exclusion', 'gambling awareness', 'play responsibly', 'gamcare', 'gambleaware'];
const rgCount = responsibleGamblingKeywords.filter(kw => text.includes(kw)).length;
if (rgCount >= 3 && externalCasinoCount === 0) {
  casinoScore += 7;
  indicators.push(`✓ Responsible gambling tools (${rgCount}) (CASINO)`);
}

// 5. Gaming license for THIS casino
const licenseKeywords = ['licensed and regulated by', 'our gaming license', 'license number', 'regulated by mga', 'regulated by ukgc'];
const licenseCount = countOccurrences(text, licenseKeywords);
if (licenseCount >= 1 && externalCasinoCount === 0) {
  casinoScore += 6;
  indicators.push(`✓ Gaming license info (${licenseCount}) (CASINO)`);
}

// === CLASSIFICATION LOGIC ===

let classification = 'NOT_AFFILIATE';
let confidenceLevel = 'LOW';

// UPDATED LOGIC: If affiliate score is significantly higher than casino score, classify as affiliate
// even without detecting external links (in case tracking detection fails)

const scoreDifference = affiliateScore - casinoScore;

// Case 1: High affiliate score regardless of links detected
if (affiliateScore >= 25 && scoreDifference >= 10) {
  classification = 'AFFILIATE';
  confidenceLevel = affiliateScore >= 35 ? 'VERY_HIGH' : 'HIGH';
}
// Case 2: Medium-high affiliate score with positive difference
else if (affiliateScore >= 18 && scoreDifference >= 5) {
  classification = 'AFFILIATE';
  confidenceLevel = 'HIGH';
}
// Case 3: 5+ outbound casino links detected
else if (externalCasinoCount >= 5) {
  classification = 'AFFILIATE';
  confidenceLevel = affiliateScore >= 20 ? 'VERY_HIGH' : 'HIGH';
}
// Case 4: 3-4 outbound casino links
else if (externalCasinoCount >= 3) {
  classification = 'AFFILIATE';
  confidenceLevel = affiliateScore >= 15 ? 'HIGH' : 'MEDIUM';
}
// Case 5: Some affiliate signals with positive score difference
else if (affiliateScore >= 12 && scoreDifference > 0) {
  classification = 'AFFILIATE';
  confidenceLevel = 'MEDIUM';
}
// Case 6: Strong casino signals
else if (casinoScore >= 15 && casinoScore > affiliateScore) {
  classification = 'NOT_AFFILIATE';
  confidenceLevel = 'VERY_HIGH';
}
// Case 7: Medium casino signals
else if (casinoScore >= 10 && casinoScore > affiliateScore) {
  classification = 'NOT_AFFILIATE';
  confidenceLevel = 'HIGH';
}
// Case 8: Casino score higher
else if (casinoScore > affiliateScore) {
  classification = 'NOT_AFFILIATE';
  confidenceLevel = 'MEDIUM';
}
// Default: Not affiliate (low confidence)
else {
  classification = 'NOT_AFFILIATE';
  confidenceLevel = 'LOW';
}

// Output result
return {
  json: {
    id: $input.first().json.id || '',
    url: inputUrl,
    country: $input.first().json.country || '',
    domain: $input.first().json.domain || '',
    domain_for_searching: $input.first().json.domain_for_searching || '',
    classification: classification,
    confidence: confidenceLevel,
    affiliateScore: affiliateScore,
    casinoScore: casinoScore,
    scoreDifference: scoreDifference,
    indicatorsFound: indicators.length,
    indicators: indicators,
    externalCasinoLinks: externalCasinoCount,
  }
};

const body = $input.first().json.body;

return body.map(item => ({
  json: {
    ...item,
    domain_for_searching: item.domain.replace(/^https?:\/\/(www\.)?/, '')
  }
}));
